from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    def _ordinal(n: str) -> str:
        """Convert ordinal prefix to English word."""
        return {"1st": "first", "2nd": "second", "3rd": "third", "4th": "fourth", "5th": "fifth"}.get(n, n.lower())

    # Build entity relationships map for nested entities
    entity_map = {}
    for t in triples:
        s = _clean(t.subject)
        o = _clean(t.object)
        if s not in entity_map:
            entity_map[s] = []
        entity_map[s].append((t.predicate, o))

    subject = _clean(triples[0].subject)

    # Collect facts with their types
    facts = {
        "location": [],
        "operational": [],
        "runway": [],
        "identifier": [],
        "other": []
    }

    for t in triples:
        s = _clean(t.subject)
        p = t.predicate
        o = _clean(t.object)

        # Skip if subject is not the main airport (it's a related entity)
        if s != subject:
            continue

        if p == "cityServed":
            facts["location"].append(f"serves {o}")
        elif p == "location":
            facts["location"].append(f"located in {o}")
        elif p == "country":
            facts["location"].append(f"in {o}")
        elif p == "isPartOf":
            facts["location"].append(f"part of {o}")
        elif p == "elevationAboveTheSeaLevel":
            facts["location"].append(f"at an elevation of {o} metres above sea level")
        elif p == "elevationAboveTheSeaLevelInFeet":
            facts["location"].append(f"at an elevation of {o} feet above sea level")
        elif p == "elevationAboveTheSeaLevelInMetres":
            facts["location"].append(f"at an elevation of {o} metres above sea level")
        elif p.endswith("RunwayLengthFeet"):
            idx = _ordinal(p.split("Runway")[0])
            facts["runway"].append(f"{idx} runway is {o} feet long")
        elif p.endswith("RunwayLengthMetre"):
            idx = _ordinal(p.split("Runway")[0])
            facts["runway"].append(f"{idx} runway is {o} metres long")
        elif p == "runwayLength":
            facts["runway"].append(f"runway length of {o}")
        elif p.endswith("RunwaySurfaceType") or p == "runwaySurfaceType":
            facts["runway"].append(f"{o} surface")
        elif p == "runwayName":
            facts["runway"].append(f"named {o}")
        elif p == "operatingOrganisation":
            facts["operational"].append(f"operated by {o}")
        elif p == "owner":
            facts["operational"].append(f"owned by {o}")
        elif p == "icaoLocationIdentifier":
            facts["identifier"].append(f"ICAO code {o}")
        elif p == "iataLocationIdentifier":
            facts["identifier"].append(f"IATA code {o}")
        elif p == "locationIdentifier":
            facts["identifier"].append(f"code {o}")
        else:
            facts["other"].append(f"{p.replace('_', ' ')} of {o}")

    # Build the sentence with proper grammar
    sentence_parts = [subject]

    # Add location facts
    if facts["location"]:
        if len(facts["location"]) == 1:
            sentence_parts.append(f" {facts['location'][0]}")
        else:
            location_text = ", ".join(facts["location"])
            sentence_parts.append(f" {location_text}")

    # Add runway facts
    if facts["runway"]:
        if len(facts["runway"]) == 1:
            sentence_parts.append(f" with {facts['runway'][0]}")
        else:
            runway_text = ", ".join(facts["runway"])
            sentence_parts.append(f" with {runway_text}")

    # Add operational facts
    if facts["operational"]:
        if len(facts["operational"]) == 1:
            sentence_parts.append(f", {facts['operational'][0]}")
        else:
            operational_text = ", ".join(facts["operational"])
            sentence_parts.append(f", {operational_text}")

    # Add identifier facts
    if facts["identifier"]:
        if len(facts["identifier"]) == 1:
            sentence_parts.append(f", with {facts['identifier'][0]}")
        else:
            identifier_text = ", ".join(facts["identifier"])
            sentence_parts.append(f", with {identifier_text}")

    # Add other facts
    if facts["other"]:
        other_text = ", ".join(facts["other"])
        sentence_parts.append(f", including {other_text}")

    sentence = "".join(sentence_parts) + "."

    # Clean up any double commas or spaces
    import re
    sentence = re.sub(r',\s*,', ',', sentence)
    sentence = re.sub(r'  +', ' ', sentence)
    sentence = sentence.strip()

    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END
